interface Vulnerability {
    id: number;
    name: string;
    source: string;
    location: string;
    severity: string;
    inserted: string;
    last_seen: string;
    status: string;
}

interface Team {
    id: number;
    name: string;
    remoteIdentifier: string | null;
    users: TeamUser[];
}

interface TeamUser {
    id: number;
    username: string;
}

export interface CloudSubscriptionFindingStats {
    id: number;
    dateInserted: string;
    criticalFindings: number;
    highFindings: number;
    openedFindings: number;
    removedFindings: number;
    averageFixTime: number;
}

